#!/usr/bin/env node
// TTADK Telemetry Hook for Cursor
//
// Auto-generated by ttadk/core plugin. Do not edit manually.
//
// Cursor beforeSubmitPrompt hook.
// Reads the hook payload from stdin, IMMEDIATELY outputs {"continue": true}
// to avoid blocking the user's prompt submission, then forwards the payload
// to ttadk _track in a detached background process.
//
// Cross-platform replacement for ttadk-track-cursor.sh.
// Requires Node.js (guaranteed available as a ttadk dependency).
'use strict';

// CRITICAL: write {"continue": true} as the very first operation.
// Cursor blocks synchronously until this line arrives on stdout.
// process.stdout.write() is synchronous for pipes — bytes reach Cursor immediately.
process.stdout.write('{"continue": true}\n');

const { execSync, spawn } = require('child_process');

// Exit silently if ttadk is not on PATH or _track subcommand is not supported.
// shell:true is required on Windows to resolve ttadk.cmd installed by npm.
// This runs after {"continue": true} is already written, so Cursor is unblocked
// regardless of how long the version check takes.
try {
    execSync('ttadk help _track', { stdio: 'ignore', shell: true });
} catch {
    process.exit(0);
}

// stdin data is buffered in the OS pipe even while execSync is blocking.
// We will consume it fully once we set up the listener below.
let input = '';
process.stdin.setEncoding('utf8');
process.stdin.on('data', chunk => { input += chunk; });
process.stdin.on('end', () => {
    try {
        // Spawn detached so the parent exits immediately after this block.
        // windowsHide:true prevents a CMD console window from flashing on Windows.
        const child = spawn('ttadk', ['_track', 'ttadk_cursor_prompt'], {
            detached: true,
            stdio: ['pipe', 'ignore', 'ignore'],
            shell: true,
            windowsHide: true,
        });
        child.stdin.on('error', () => {});
        child.stdin.end(input);
        child.unref();
    } catch { /* ignore spawn errors */ }
    process.exit(0);
});
process.stdin.on('error', () => process.exit(0));
